// The pediatric BP-PERCENTILE dataset (AAP 2017), loaded onto the curated-dataset
// framework (issue #860 Track B). Copies the growth-charts.ts shape (meta + entries):
// import the envelope JSON (generated by scripts/gen-bp-percentiles.ts), validate it once
// with loadDataset(), and expose the normative-row ENTRIES, the dataset-level `meta`
// scalars, and a rebuilt per-sex BpRow[] map the pure interpretation consumes. Identity
// is the composite `key` (`<sex>:<age>:<pct>`, fieldStrategy) — one entry per normative
// row. The registry lists this for the linter; lib/bp-percentiles.ts is the pure
// percentile / AAP-category lookup over these entries. Pure — no DB, no network.

import rawBp from "./data/bp-percentiles.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  BpPercentileEntry,
  BpPercentilesMeta,
  BpRow,
  BpSex,
} from "@/scripts/gen-bp-percentiles";

export type {
  BpPercentileEntry,
  BpPercentilesMeta,
  BpRow,
  BpSex,
} from "@/scripts/gen-bp-percentiles";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const bpPercentilesDataset = loadDataset<
  BpPercentileEntry,
  BpPercentilesMeta
>(rawBp);

// Identity strategy: the composite `key` (`<sex>:<age>:<pct>`, case-folded). For the
// linter/harness — each normative row has a unique key, so identity resolves and an
// unknown key refuses (null).
export const bpPercentileKeyStrategy = fieldStrategy("key");

// The normative-row entries (curated order) and the dataset-level scalars.
export const BP_PERCENTILE_ENTRIES: BpPercentileEntry[] =
  bpPercentilesDataset.entries;
export const BP_META: BpPercentilesMeta =
  bpPercentilesDataset.meta as BpPercentilesMeta;

// A per-sex BpRow[] map rebuilt from the entries, keyed by sex with the identity fields
// (key/sex) stripped back to the domain BpRow shape (age/pct/sbp/dbp) — byte-for-byte, so
// the pure interpretation's `DATA.sexes[sex]` behaves exactly as it did over the old
// `{ sexes }` map. Order is preserved (male rows then female, age/percentile order).
export const BP_SEXES_MAP: { male: BpRow[]; female: BpRow[] } = (() => {
  const out: { male: BpRow[]; female: BpRow[] } = { male: [], female: [] };
  for (const e of BP_PERCENTILE_ENTRIES) {
    const sex: BpSex = e.sex;
    out[sex].push({ age: e.age, pct: e.pct, sbp: e.sbp, dbp: e.dbp });
  }
  return out;
})();
